function safeString(value, maxLen) {
  const text = String(value ?? '').replace(/\s+/g, ' ').trim();
  return maxLen ? text.slice(0, maxLen) : text;
}

function cleanupText(text) {
  return String(text ?? '')
    .replace(/\s+/g, ' ')
    .replace(/\s+([,.!?;:])/g, '$1')
    .trim();
}

function normalizeText(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function isPlainObject(value) {
  return !!value && typeof value === 'object' && !Array.isArray(value);
}

function isValidCopyObject(obj) {
  return !!(
    obj &&
    typeof obj === 'object' &&
    (
      obj.hero_hook ||
      obj.reason_to_buy ||
      obj.cta_line ||
      obj.button_title ||
      obj.button_description ||
      obj.email_reason
    )
  );
}

function parseJsonFromText(raw) {
  if (!raw) return null;

  if (isPlainObject(raw)) {
    if (isValidCopyObject(raw)) return raw;
    if (isPlainObject(raw.json) && isValidCopyObject(raw.json)) return raw.json;
    if (isPlainObject(raw.output) && isValidCopyObject(raw.output)) return raw.output;
  }

  const text = String(raw).trim();
  if (!text) return null;

  try {
    const direct = JSON.parse(text);
    if (isValidCopyObject(direct)) return direct;
    if (isPlainObject(direct?.json) && isValidCopyObject(direct.json)) return direct.json;
  } catch (_) {}

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced) {
    try {
      const parsed = JSON.parse(fenced[1]);
      if (isValidCopyObject(parsed)) return parsed;
      if (isPlainObject(parsed?.json) && isValidCopyObject(parsed.json)) return parsed.json;
    } catch (_) {}
  }

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const candidate = text.slice(start, end + 1);
    try {
      const parsed = JSON.parse(candidate);
      if (isValidCopyObject(parsed)) return parsed;
      if (isPlainObject(parsed?.json) && isValidCopyObject(parsed.json)) return parsed.json;
    } catch (_) {}
  }

  return null;
}

function extractTextFromAny(value) {
  if (value == null) return '';

  if (typeof value === 'string') return value;

  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (typeof item === 'string') return item;
        if (isPlainObject(item)) {
          return (
            item.text ||
            item.content ||
            item.output ||
            item.message ||
            ''
          );
        }
        return '';
      })
      .filter(Boolean)
      .join('\n');
  }

  if (isPlainObject(value)) {
    if (typeof value.content === 'string') return value.content;
    if (typeof value.text === 'string') return value.text;
    if (typeof value.output === 'string') return value.output;
    if (typeof value.message === 'string') return value.message;

    if (Array.isArray(value.content)) {
      return extractTextFromAny(value.content);
    }

    if (Array.isArray(value.messages)) {
      return extractTextFromAny(value.messages);
    }

    if (isPlainObject(value.message)) {
      return extractTextFromAny(value.message);
    }

    if (isPlainObject(value.output)) {
      return extractTextFromAny(value.output);
    }
  }

  return '';
}

function collectCandidates(j) {
  return [
    j,
    j.output,
    j.response,
    j.result,
    j.data,
    j.message,
    j.content,
    j.text,
    j.output?.content,
    j.output?.text,
    j.output?.message,
    j.response?.content,
    j.response?.text,
    j.response?.message,
    j.result?.content,
    j.result?.text,
    j.result?.message,
    j.data?.content,
    j.data?.text,
    j.data?.message,
    extractTextFromAny(j.output),
    extractTextFromAny(j.response),
    extractTextFromAny(j.result),
    extractTextFromAny(j.data),
    extractTextFromAny(j.message),
    extractTextFromAny(j.content),
  ].filter((v) => v !== undefined && v !== null && v !== '');
}

function resolveProductName(j) {
  return cleanupText(
    j.nome_produto ||
    j.product_name_short ||
    j.product_name ||
    j.PRODUTO_NOME ||
    j.produto_nome ||
    j.NOME_PRODUTO ||
    j.PRODUTO ||
    ''
  );
}

function resolveCategory(j) {
  return cleanupText(
    j.copy_category ||
    j.categoria_produto ||
    j.CATEGORIA ||
    j.CATEGORIA_INFERIDA ||
    ''
  );
}

function detectGender(productName, category, explicitGender) {
  const g = normalizeText(explicitGender);
  if (g === 'f' || g === 'feminino') return 'F';
  if (g === 'm' || g === 'masculino') return 'M';

  const text = normalizeText(`${productName || ''} ${category || ''}`);

  const feminineTerms = [
    'chopeira',
    'adega',
    'cervejeira',
    'maquina',
    'máquina',
    'fritadeira',
    'lavadora',
    'coifa',
    'geladeira',
    'cafeteira',
    'air fryer',
    'batedeira',
    'sanduicheira',
    'placa',
    'bomba'
  ];

  const masculineTerms = [
    'ar-condicionado',
    'ar condicionado',
    'refrigerador',
    'frigobar',
    'freezer',
    'forno',
    'micro-ondas',
    'microondas',
    'purificador',
    'ventilador',
    'climatizador',
    'bebedouro',
    'cooktop',
    'aspirador',
    'controle',
    'motor',
    'compressor',
    'filtro secador'
  ];

  if (feminineTerms.some(term => text.includes(term))) return 'F';
  if (masculineTerms.some(term => text.includes(term))) return 'M';

  return 'M';
}

function getMainNoun(productName) {
  const text = normalizeText(productName);
  const nouns = [
    'chopeira',
    'adega',
    'cervejeira',
    'maquina de bebidas',
    'geladeira',
    'cafeteira',
    'air fryer',
    'fritadeira',
    'batedeira',
    'sanduicheira',
    'placa',
    'bomba',
    'ar condicionado',
    'refrigerador',
    'frigobar',
    'freezer',
    'forno',
    'micro-ondas',
    'microondas',
    'cooktop',
    'ventilador',
    'controle',
    'motor',
    'compressor',
    'filtro secador'
  ];

  return nouns.find(noun => text.includes(noun)) || '';
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function fixGenderAgreement(text, gender, productName) {
  let t = String(text || '');
  if (!t || gender !== 'F') return t;

  const noun = getMainNoun(productName);
  if (!noun) return t;

  const nounPattern = escapeRegExp(noun).replace(/\s+/g, '\\s+');

  t = t
    .replace(new RegExp(`\\bSeu\\s+${nounPattern}\\b`, 'gi'), (m) => /^[A-Z]/.test(m) ? `Sua ${noun}` : `sua ${noun}`)
    .replace(new RegExp(`\\bUm\\s+${nounPattern}\\b`, 'gi'), (m) => /^[A-Z]/.test(m) ? `Uma ${noun}` : `uma ${noun}`)
    .replace(new RegExp(`\\bO\\s+${nounPattern}\\b`, 'gi'), (m) => /^[A-Z]/.test(m) ? `A ${noun}` : `a ${noun}`)
    .replace(new RegExp(`\\bEsse\\s+${nounPattern}\\b`, 'gi'), (m) => /^[A-Z]/.test(m) ? `Essa ${noun}` : `essa ${noun}`)
    .replace(new RegExp(`\\bEste\\s+${nounPattern}\\b`, 'gi'), (m) => /^[A-Z]/.test(m) ? `Esta ${noun}` : `esta ${noun}`)
    .replace(/\bSeu\b/g, 'Sua')
    .replace(/\bseu\b/g, 'sua')
    .replace(/\bEsse\b/g, 'Essa')
    .replace(/\besse\b/g, 'essa');

  return t;
}

const j = $json ?? {};

let parsed = null;
let parsedSource = '';

for (const candidate of collectCandidates(j)) {
  const maybe = parseJsonFromText(candidate);
  if (isValidCopyObject(maybe)) {
    parsed = maybe;
    parsedSource = typeof candidate === 'string' ? 'text' : 'object';
    break;
  }
}

const fallback = {
  hero_hook: j.fallback_copy_hook || '',
  reason_to_buy: j.fallback_copy_reason || '',
  cta_line: j.fallback_copy_cta || '',
  button_title: j.fallback_button_title || '',
  button_description: j.fallback_button_description || '',
  email_reason: j.fallback_email_reason || ''
};

const productName = resolveProductName(j);
const category = resolveCategory(j);
const gender = detectGender(productName, category, j.product_gender);

const hero_hook = cleanupText(
  fixGenderAgreement(
    safeString(parsed?.hero_hook || fallback.hero_hook, 110),
    gender,
    productName
  )
);

const reason_to_buy = cleanupText(
  fixGenderAgreement(
    safeString(parsed?.reason_to_buy || fallback.reason_to_buy, 180),
    gender,
    productName
  )
);

const cta_line = cleanupText(
  fixGenderAgreement(
    safeString(parsed?.cta_line || fallback.cta_line, 100),
    gender,
    productName
  )
);

const button_title = cleanupText(
  fixGenderAgreement(
    safeString(parsed?.button_title || fallback.button_title, 35),
    gender,
    productName
  )
);

const button_description = cleanupText(
  fixGenderAgreement(
    safeString(parsed?.button_description || fallback.button_description, 120),
    gender,
    productName
  )
);

const email_reason = cleanupText(
  fixGenderAgreement(
    safeString(parsed?.email_reason || fallback.email_reason, 180),
    gender,
    productName
  )
);

return [{
  json: {
    ...j,
    ai_copy_hook: hero_hook,
    ai_copy_reason: reason_to_buy,
    ai_copy_cta: cta_line,
    ai_button_title: button_title,
    ai_button_description: button_description,
    ai_email_reason: email_reason,
    ai_copy_parse_ok: !!parsed,
    ai_copy_parse_source: parsedSource || 'fallback',
    ai_gender_detected: gender,
    ai_product_name_used: productName || '',
    ai_category_used: category || '',
    ai_raw_output_preview: safeString(
      extractTextFromAny(j.output) ||
      extractTextFromAny(j.response) ||
      extractTextFromAny(j.result) ||
      extractTextFromAny(j.data) ||
      '',
      500
    )
  }
}];

const j = $json ?? {};

function normalizeText(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function cleanSpaces(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function capitalize(value) {
  const text = cleanSpaces(value);
  return text ? text.charAt(0).toUpperCase() + text.slice(1) : '';
}

function toTitleCase(value) {
  return cleanSpaces(value)
    .toLowerCase()
    .replace(/\b([a-zà-ÿ])/g, (match) => match.toUpperCase());
}

function getFirstName(fullName) {
  const raw = cleanSpaces(String(fullName ?? '').replace(/[^\p{L}\s'-]/gu, ' '));
  if (!raw) return 'Cliente';

  const parts = raw.split(/\s+/).filter(Boolean);
  const first = parts[0] || 'Cliente';

  return toTitleCase(first);
}

function getBrazilDateContext() {
  const now = new Date();

  const parts = new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    weekday: 'long',
    hour: '2-digit',
    month: '2-digit',
    hour12: false,
  }).formatToParts(now);

  const map = Object.fromEntries(
    parts
      .filter((p) => p.type !== 'literal')
      .map((p) => [p.type, p.value])
  );

  const weekdayName = String(map.weekday || '').toLowerCase();
  const hour = Number(map.hour || 0);
  const month = Number(map.month || 1);

  const period =
    hour < 12 ? 'manhã' :
    hour < 18 ? 'tarde' :
    'noite';

  const season =
    [12, 1, 2].includes(month) ? 'verão' :
    [3, 4, 5].includes(month) ? 'outono' :
    [6, 7, 8].includes(month) ? 'inverno' :
    'primavera';

  const isWeekend = weekdayName === 'sábado' || weekdayName === 'domingo';

  return { weekdayName, hour, month, period, season, isWeekend };
}

function getGreeting(period, firstName) {
  if (period === 'manhã') return `Bom dia, ${firstName}!`;
  if (period === 'tarde') return `Boa tarde, ${firstName}!`;
  return `Boa noite, ${firstName}!`;
}

function inferCategory(rawName, rawLink) {
  const text = normalizeText(`${rawName || ''} ${rawLink || ''}`);

  if (/(chopeira|chopp|bierhaus|bier cooler|cervejeira|adega|maquina de bebidas|máquina de bebidas|slushi|ice frozen|frozen)/.test(text)) {
    return 'bebidas';
  }

  if (/(ar condicionado|ar-condicionado|climatiz|split|ventilador|ventilacao|ventilação|umidificador|desumidificador)/.test(text)) {
    return 'climatizacao';
  }

  if (/(air fryer|fritadeira|forno|micro-ondas|microondas|cooktop|fogao|fogão|cafeteira|liquidificador|batedeira|sanduicheira|espremedor|grill|mixer|cozinha)/.test(text)) {
    return 'cozinha';
  }

  if (/(geladeira|refrigerador|frigobar|freezer)/.test(text)) {
    return 'refrigeracao';
  }

  if (/(ferrament|parafus|solda|bomba|motor|peca|peça|controle|placa|manutenc|manutenção|kit instalacao|kit instalação|filtro secador|tubo cobre|valvula|válvula|compressor|capacitor|termostato)/.test(text)) {
    return 'manutencao';
  }

  return 'casa';
}

function simplifyProductName(rawName, category) {
  const original = cleanSpaces(rawName);
  if (!original) return 'Produto';

  const normalized = normalizeText(original);

  if (/chopeira/.test(normalized) && /eos/.test(normalized) && /bierhaus/.test(normalized)) return 'Chopeira EOS Bierhaus';
  if (/cervejeira/.test(normalized) && /eos/.test(normalized)) return 'Cervejeira EOS';
  if (/adega/.test(normalized) && /eos/.test(normalized)) return 'Adega EOS';
  if (/(maquina de bebidas|máquina de bebidas|ice frozen|slushi)/.test(normalized) && /eos/.test(normalized)) return 'Máquina de bebidas EOS';
  if (/(ar condicionado|ar-condicionado|split)/.test(normalized)) return 'Ar-condicionado';
  if (/frigobar/.test(normalized)) return 'Frigobar';
  if (/refrigerador/.test(normalized)) return 'Refrigerador';
  if (/geladeira/.test(normalized)) return 'Geladeira';
  if (/freezer/.test(normalized)) return 'Freezer';
  if (/micro-ondas|microondas/.test(normalized)) return 'Micro-ondas';
  if (/cooktop/.test(normalized)) return 'Cooktop';
  if (/air fryer|fritadeira/.test(normalized)) return 'Air fryer';
  if (/cafeteira/.test(normalized)) return 'Cafeteira';
  if (/liquidificador/.test(normalized)) return 'Liquidificador';
  if (/batedeira/.test(normalized)) return 'Batedeira';
  if (/sanduicheira/.test(normalized)) return 'Sanduicheira';
  if (/ventilador/.test(normalized)) return 'Ventilador';
  if (/umidificador/.test(normalized)) return 'Umidificador';
  if (/desumidificador/.test(normalized)) return 'Desumidificador';
  if (/controle/.test(normalized)) return 'Controle';
  if (/placa/.test(normalized)) return 'Placa';
  if (/bomba/.test(normalized)) return 'Bomba';
  if (/motor/.test(normalized)) return 'Motor';
  if (/compressor/.test(normalized)) return 'Compressor';
  if (/filtro secador/.test(normalized)) return 'Filtro secador';
  if (/tubo cobre/.test(normalized)) return 'Tubo de cobre';

  const cleaned = cleanSpaces(
    original
      .replace(/\b\d+[.,]?\d*\s*(litros?|l|btus?|garrafas?|kg|w|kw|cm|mm|m)\b/gi, ' ')
      .replace(/\b(110v|127v|220v|bivolt)\b/gi, ' ')
      .replace(/\b(inverter|digital|compacta|compacto|premium|smart|all black|all-white|quente e frio|frio)\b/gi, ' ')
      .replace(/\b(com compressor|dual zone|vertical|expositora|split)\b/gi, ' ')
      .replace(/\b([A-Z]{2,}\d+[A-Z0-9-]*)\b/g, ' ')
      .replace(/[|/-]\s*frigelar.*$/i, ' ')
  );

  if (cleaned) return cleaned;

  const fallbackMap = {
    bebidas: 'Produto para bebidas',
    climatizacao: 'Climatizador',
    cozinha: 'Produto de cozinha',
    refrigeracao: 'Produto de refrigeração',
    manutencao: 'Item de manutenção',
    casa: 'Produto',
  };

  return fallbackMap[category] || 'Produto';
}

function inferGrammar(productName, category) {
  const text = normalizeText(productName);

  const femininePatterns = [
    /chopeira/,
    /cervejeira/,
    /adega/,
    /maquina de bebidas/,
    /máquina de bebidas/,
    /geladeira/,
    /cafeteira/,
    /fritadeira/,
    /air fryer/,
    /batedeira/,
    /sanduicheira/,
    /placa/,
    /bomba/,
    /peca/,
    /peça/,
    /valvula/,
    /válvula/,
  ];

  const masculinePatterns = [
    /ar condicionado/,
    /ventilador/,
    /umidificador/,
    /desumidificador/,
    /refrigerador/,
    /frigobar/,
    /freezer/,
    /micro-ondas/,
    /forno/,
    /cooktop/,
    /fogao/,
    /fogão/,
    /liquidificador/,
    /espremedor/,
    /grill/,
    /mixer/,
    /controle/,
    /motor/,
    /compressor/,
    /capacitor/,
    /filtro secador/,
    /tubo de cobre/,
    /kit/,
  ];

  if (femininePatterns.some((pattern) => pattern.test(text))) {
    return {
      gender: 'feminino',
      definite: 'a',
      indefinite: 'uma',
      demonstrative: 'essa',
      possessive: 'sua',
    };
  }

  if (masculinePatterns.some((pattern) => pattern.test(text))) {
    return {
      gender: 'masculino',
      definite: 'o',
      indefinite: 'um',
      demonstrative: 'esse',
      possessive: 'seu',
    };
  }

  if (category === 'climatizacao' || category === 'refrigeracao' || category === 'manutencao') {
    return {
      gender: 'masculino',
      definite: 'o',
      indefinite: 'um',
      demonstrative: 'esse',
      possessive: 'seu',
    };
  }

  return {
    gender: 'feminino',
    definite: 'a',
    indefinite: 'uma',
    demonstrative: 'essa',
    possessive: 'sua',
  };
}

function getBenefitDirection(category, season, isWeekend, period) {
  if (category === 'climatizacao') {
    if (season === 'verão' || season === 'primavera') {
      return 'conforto, temperatura ideal, ambiente agradável e rotina mais leve nos dias quentes';
    }
    return 'conforto, bem-estar e ambiente mais agradável no dia a dia';
  }

  if (category === 'bebidas') {
    return isWeekend
      ? 'bebida na temperatura certa, lazer em casa, receber bem e curtir bons momentos'
      : 'praticidade para servir bebida gelada, experiência em casa e momentos mais gostosos';
  }

  if (category === 'cozinha') {
    return period === 'manhã'
      ? 'agilidade, praticidade e rotina mais fácil desde cedo'
      : 'praticidade, conveniência e ganho real no dia a dia';
  }

  if (category === 'refrigeracao') {
    return 'praticidade, conservação, organização e conveniência na rotina da casa';
  }

  if (category === 'manutencao') {
    return 'resolver a necessidade com praticidade, sem enrolação e com objetivo claro';
  }

  return 'benefício real, melhora perceptível no dia a dia e linguagem natural';
}

function getForbiddenDirections(category) {
  const map = {
    bebidas: 'evite problema, urgência falsa, linguagem técnica, retrabalho e tom de solução de defeito',
    climatizacao: 'evite exagero, pressão, urgência falsa e tecnicismo desnecessário',
    cozinha: 'evite drama, tom publicitário demais e frases genéricas',
    refrigeracao: 'evite exagero, artificialidade e pressão de venda',
    manutencao: 'evite drama, promessas não confirmadas e urgência inventada',
    casa: 'evite frases vagas, pressão comercial e linguagem robótica',
  };

  return map[category] || map.casa;
}

function buildFallback(category, productName, grammar, context) {
  const product = cleanSpaces(productName) || 'produto';
  const possessive = grammar.possessive;
  const demonstrative = grammar.demonstrative;

  if (category === 'climatizacao') {
    return {
      hook:
        context.season === 'verão' || context.season === 'primavera'
          ? `${capitalize(possessive)} ${product} pode deixar o ambiente muito mais agradável nos próximos dias.`
          : `${capitalize(possessive)} ${product} pode trazer mais conforto para a rotina de casa.`,
      reason: `É o tipo de compra que melhora o ambiente e faz diferença no uso real do dia a dia.`,
      cta: `Se quiser, eu posso te ajudar a retomar por aqui.`,
      buttonTitle: `Retomar compra`,
      buttonDescription: `Retome a compra do ${product} com praticidade.`,
      emailReason: `${capitalize(possessive)} ${product} pode trazer mais conforto e bem-estar para a rotina.`,
    };
  }

  if (category === 'bebidas') {
    return {
      hook: context.isWeekend
        ? `${capitalize(possessive)} ${product} combina muito com bons momentos em casa e tudo na temperatura certa.`
        : `${capitalize(possessive)} ${product} pode deixar seus próximos momentos em casa ainda melhores.`,
      reason: `Faz sentido para quem quer mais praticidade, experiência e prazer na hora de servir ou receber.`,
      cta: `Se quiser, eu deixo a retomada bem simples por aqui.`,
      buttonTitle: `Retomar compra`,
      buttonDescription: `Retome a compra do ${product} com facilidade.`,
      emailReason: `${capitalize(possessive)} ${product} faz sentido para quem quer mais praticidade e uma experiência melhor em casa.`,
    };
  }

  if (category === 'cozinha') {
    return {
      hook: `${capitalize(possessive)} ${product} tem tudo para virar praticidade de verdade no dia a dia.`,
      reason: `É aquele tipo de compra que costuma facilitar a rotina já no primeiro uso.`,
      cta: `Se quiser, eu sigo com você por aqui para retomar sem complicação.`,
      buttonTitle: `Ver compra`,
      buttonDescription: `Retome a compra do ${product} com praticidade.`,
      emailReason: `${capitalize(possessive)} ${product} pode simplificar sua rotina e trazer conveniência no uso diário.`,
    };
  }

  if (category === 'refrigeracao') {
    return {
      hook: `${capitalize(possessive)} ${product} pode trazer mais praticidade e organização para a rotina da casa.`,
      reason: `É um item que costuma fazer sentido no dia a dia, tanto pelo uso constante quanto pela conveniência.`,
      cta: `Se quiser, eu posso te ajudar a retomar essa compra por aqui.`,
      buttonTitle: `Retomar compra`,
