function tryParseJson(value) {
  if (value == null) return null;

  if (typeof value === 'object' && !Array.isArray(value)) {
    return value;
  }

  const text = safeText(value, '');
  if (!text) return null;

  try {
    return JSON.parse(text);
  } catch (_) {}

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced) {
    try {
      return JSON.parse(fenced[1]);
    } catch (_) {}
  }

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start >= 0 && end > start) {
    try {
      return JSON.parse(text.slice(start, end + 1));
    } catch (_) {}
  }

  return null;
}

function extractTextFromAny(value) {
  if (value == null) return '';

  if (typeof value === 'string') return value;

  if (Array.isArray(value)) {
    return value.map(extractTextFromAny).filter(Boolean).join('\n');
  }

  if (typeof value === 'object') {
    return (
      extractTextFromAny(value.text) ||
      extractTextFromAny(value.content) ||
      extractTextFromAny(value.output) ||
      extractTextFromAny(value.message) ||
      ''
    );
  }

  return '';
}

function extractAiFields(record) {
