    tryParseJson(record.output) ||
    tryParseJson(record.ai_output_json) ||
    tryParseJson(record.response) ||
    tryParseJson(record.result) ||
    tryParseJson(record.message) ||
    tryParseJson(record.content) ||
    null;

  const plainOutput =
    extractTextFromAny(record.output) ||
    extractTextFromAny(record.response) ||
    extractTextFromAny(record.result) ||
    extractTextFromAny(record.message) ||
    extractTextFromAny(record.content) ||
    '';

  return {
    hook: safeText(
      record.ai_copy_hook ||
      record.hero_hook ||
      parsedOutput?.hero_hook ||
      parsedOutput?.hook ||
