const lead = $('IF | Pronto para disparo?').item.json ?? {};
const http = $json ?? {};

function decodeHtml(value) {
  const map = {
    '&amp;': '&',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&lt;': '<',
    '&gt;': '>',
    '&nbsp;': ' ',
  };

  return String(value ?? '').replace(
    /&amp;|&quot;|&#39;|&apos;|&lt;|&gt;|&nbsp;/g,
    (match) => map[match] || match
  );
}

function cleanSpaces(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function stripTags(value) {
  return cleanSpaces(decodeHtml(String(value ?? '').replace(/<[^>]+>/g, ' ')));
}

function getHtmlPayload(source) {
  const candidates = [
    source?.body,
    source?.data,
    source?.html,
    source?.content,
    typeof source === 'string' ? source : '',
  ];

  for (const item of candidates) {
    if (typeof item === 'string' && item.trim()) return item;
  }

  return JSON.stringify(source ?? {});
}

function getStatusCode(source, html) {
  const code = Number(source?.statusCode || source?.status || source?.code || 0);
  if (Number.isFinite(code) && code > 0) return code;
  return html && html !== '{}' ? 200 : 0;
}

function parseAttributes(tag) {
  const attrs = {};
  const regex = /([:@\w-]+)\s*=\s*(?:"([^"]*)"|'([^']*)'|([^\s>]+))/g;

  let match;
  while ((match = regex.exec(tag)) !== null) {
    const key = String(match[1] || '').toLowerCase();
    const value = match[2] ?? match[3] ?? match[4] ?? '';
    attrs[key] = decodeHtml(value);
  }

  return attrs;
}

function extractMetaContent(html, keys) {
  const wanted = new Set([].concat(keys).map((k) => String(k).toLowerCase()));
  const tags = html.match(/<meta\b[^>]*>/gi) || [];

  for (const tag of tags) {
    const attrs = parseAttributes(tag);
    const names = [attrs.property, attrs.name, attrs.itemprop]
      .filter(Boolean)
      .map((v) => String(v).toLowerCase());

    if (!attrs.content) continue;
    if (names.some((name) => wanted.has(name))) {
      return cleanSpaces(attrs.content);
    }
  }

  return '';
}

function extractTitle(html) {
  const match = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return match ? stripTags(match[1]) : '';
}

function getJsonLdBlocks(html) {
  const blocks = [];
  const regex = /<script\b[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;

  let match;
  while ((match = regex.exec(html)) !== null) {
    if (match[1]) blocks.push(match[1].trim());
  }

  return blocks;
}

function safeJsonParse(raw) {
  const attempts = [
    raw,
    raw
      .replace(/^\s*<!--/, '')
      .replace(/-->\s*$/, '')
      .replace(/<!\[CDATA\[/g, '')
      .replace(/\]\]>/g, '')
      .trim(),
  ];

  for (const attempt of attempts) {
    try {
      return JSON.parse(attempt);
    } catch (_) {}
  }

  return null;
}

function walkJson(node, visit) {
  if (!node || typeof node !== 'object') return;

  visit(node);

  if (Array.isArray(node)) {
    for (const item of node) walkJson(item, visit);
    return;
  }

  for (const value of Object.values(node)) {
    if (value && typeof value === 'object') walkJson(value, visit);
  }
}

function hasType(node, expectedType) {
  const type = node?.['@type'];
  const list = Array.isArray(type) ? type : [type];
  return list.some((item) => String(item || '').toLowerCase() === String(expectedType).toLowerCase());
}

function pickImageFromNode(node) {
  const candidate = node?.image || node?.thumbnailUrl || node?.logo;

  if (!candidate) return '';

  if (typeof candidate === 'string') return candidate;

  if (Array.isArray(candidate)) {
    for (const item of candidate) {
      if (typeof item === 'string' && item.trim()) return item;
      if (item && typeof item === 'object' && item.url) return item.url;
    }
  }

  if (typeof candidate === 'object' && candidate.url) {
    return candidate.url;
  }

  return '';
}

function pickVideoFromNode(node) {
  const candidate = node?.video || node?.subjectOf;

  if (!candidate) return '';

  const items = Array.isArray(candidate) ? candidate : [candidate];

  for (const item of items) {
    if (typeof item === 'string' && item.trim()) return item;

    if (item && typeof item === 'object') {
      const direct =
        item.contentUrl ||
        item.embedUrl ||
        item.url ||
        item.playerType ||
        '';

      if (direct) return direct;
    }
  }

  return '';
}

function extractJsonLdData(html) {
  const result = {
    name: '',
    description: '',
    image: '',
    video: '',
  };

  const blocks = getJsonLdBlocks(html);

  for (const block of blocks) {
    const parsed = safeJsonParse(block);
    if (!parsed) continue;

    walkJson(parsed, (node) => {
      if (!result.name && typeof node.name === 'string') {
        if (hasType(node, 'Product') || hasType(node, 'Thing') || node.name) {
          result.name = cleanSpaces(decodeHtml(node.name));
        }
      }

      if (!result.description && typeof node.description === 'string') {
        result.description = stripTags(node.description);
      }

      if (!result.image) {
        const image = pickImageFromNode(node);
        if (image) result.image = image;
      }

      if (!result.video) {
        const video = pickVideoFromNode(node);
        if (video) result.video = video;
      }
    });

    if (result.name && result.description && result.image && result.video) break;
  }

  return result;
}

function normalizeUrl(rawUrl, baseUrl) {
  const value = String(rawUrl ?? '').trim();
  if (!value) return '';

  if (/^(javascript|data|mailto):/i.test(value)) return '';
  if (value.startsWith('//')) return `https:${value}`;

  try {
    return new URL(value, baseUrl).toString();
  } catch (_) {
    return value;
  }
}

function cleanupProductName(name) {
  return cleanSpaces(
    decodeHtml(name)
      .replace(/\s*[\|\-–—]\s*Frigelar.*$/i, '')
      .replace(/\s{2,}/g, ' ')
  );
}

function fallbackNameFromUrl(url) {
  try {
    const pathname = new URL(url).pathname || '';
    const parts = pathname
      .split('/')
      .filter(Boolean)
      .map((part) => decodeURIComponent(part));

    const ignored = new Set(['produto', 'produtos', 'p', 'item', 'loja', 'categoria']);
    const slug =
      [...parts].reverse().find((part) => !ignored.has(part.toLowerCase())) || 'produto';

    return cleanupProductName(
      slug
        .replace(/\.(html?|php)$/i, '')
        .replace(/[-_]+/g, ' ')
    ) || 'Produto';
  } catch (_) {
    return 'Produto';
  }
}

function extractVideoFromHtml(html) {
  const metaVideo =
    extractMetaContent(html, ['og:video', 'og:video:url', 'og:video:secure_url', 'twitter:player']) || '';
  if (metaVideo) return metaVideo;

  const patterns = [
    /https?:\/\/(?:www\.)?youtube\.com\/watch\?v=[\w-]+(?:[^\s"'<>]*)/i,
    /https?:\/\/youtu\.be\/[\w-]+(?:[^\s"'<>]*)/i,
    /https?:\/\/(?:www\.)?youtube(?:-nocookie)?\.com\/embed\/[\w-]+(?:[^\s"'<>]*)/i,
    /https?:\/\/player\.vimeo\.com\/video\/\d+(?:[^\s"'<>]*)/i,
    /https?:\/\/[^\s"'<>]+?\.(?:mp4|webm|m3u8)(?:[^\s"'<>]*)/i,
    /<video[^>]+src=["']([^"']+)["']/i,
    /<source[^>]+src=["']([^"']+)["']/i,
    /<iframe[^>]+src=["']([^"']*(?:youtube|youtu\.be|vimeo)[^"']*)["']/i,
  ];

  for (const pattern of patterns) {
    const match = html.match(pattern);
    if (!match) continue;
    const value = match[1] || match[0];
    if (value) return value;
  }

  return '';
}

const html = getHtmlPayload(http);
const jsonLd = extractJsonLdData(html);

let productName =
  extractMetaContent(html, ['og:title']) ||
  jsonLd.name ||
  extractTitle(html) ||
  fallbackNameFromUrl(lead.LINKCARRINHO);

productName = cleanupProductName(productName);

let productDescription =
  extractMetaContent(html, ['og:description', 'description']) ||
  jsonLd.description ||
  '';

productDescription = stripTags(productDescription);

let productImage =
  extractMetaContent(html, ['og:image', 'twitter:image']) ||
  jsonLd.image ||
  '';

let videoUrl =
  jsonLd.video ||
  extractVideoFromHtml(html) ||
  '';

productImage = normalizeUrl(productImage, lead.LINKCARRINHO);
videoUrl = normalizeUrl(videoUrl, lead.LINKCARRINHO);

const hasDirectVideo = Boolean(videoUrl);

if (!videoUrl) {
  videoUrl = `https://www.youtube.com/results?search_query=${encodeURIComponent(`${productName} Frigelar`)}`;
}

return [
  {
    json: {
      ...lead,
      product_name: productName || 'Produto selecionado',
      product_description: productDescription,
      product_image_url: productImage,
      video_url: videoUrl,
      video_label: hasDirectVideo ? 'Assistir vídeo do produto' : 'Ver vídeos e demonstrações',
      has_direct_video: hasDirectVideo ? 'SIM' : 'NAO',
      product_fetch_status: getStatusCode(http, html),
    },
  },
];

